 * - If github_org_id is bound to a different org → reject
 * - If this org is bound to a different github org → reject
 * - If no binding exists → create
 */
export async function enforceGitHubBinding(
  orgId: string,
  githubOrgId: string
): Promise<BindingAction> {
  // Check 1: Is this GitHub org already bound?
  const byGithub = await db
    .select({
      id: githubOrgBindings.id,
      clerkOrgId: githubOrgBindings.clerkOrgId,
    })
    .from(githubOrgBindings)
    .where(eq(githubOrgBindings.githubOrgId, githubOrgId))
    .limit(1);

  if (byGithub[0]) {
    if (byGithub[0].clerkOrgId === orgId) {
      return { action: "reinstate", bindingId: byGithub[0].id };
    }
    log.warn("[github-binding] GitHub org already bound to different org", {
      githubOrgId,
      boundTo: byGithub[0].clerkOrgId,
      requestedBy: orgId,
    });
    return { action: "reject", reason: "github_org_bound_to_other" };
  }

  // Check 2: Is this Lightfast org already bound to a different GitHub org?
  const byOrg = await db
    .select({ id: githubOrgBindings.id })
    .from(githubOrgBindings)
    .where(eq(githubOrgBindings.clerkOrgId, orgId))
    .limit(1);

  if (byOrg[0]) {
    log.warn("[github-binding] Org already bound to different GitHub org", {
      orgId,
      existingBinding: byOrg[0].id,
    });
    return { action: "reject", reason: "org_already_bound" };
  }

  return { action: "create" };
}
```

