```typescript
// ── Create/reinstate GitHub binding ──
if (providerName === "github" && githubAccount && bindingAction && installation) {
  if (bindingAction.action === "create") {
    // Use onConflictDoNothing to handle concurrent callbacks racing past
    // the enforceGitHubBinding checks. The UNIQUE indexes on clerk_org_id
    // and github_org_id are the true enforcement — the SELECTs are an
    // optimization to provide better error messages.
    const inserted = await db
      .insert(githubOrgBindings)
      .values({
        clerkOrgId: orgId,
        githubOrgId: String(githubAccount.id),
        githubOrgLogin: githubAccount.login,
        githubOrgAvatarUrl: githubAccount.avatarUrl ?? null,
        installationId: installation.id,
        boundBy: connectedBy,
        status: "active",
      })
      .onConflictDoNothing()
      .returning({ id: githubOrgBindings.id });

    if (inserted.length === 0) {
      // Race condition: another callback created the binding between
      // our SELECT checks and this INSERT. Treat as rejection.
      log.warn("[oauth/callback] GitHub binding race — conflict on insert", {
        githubOrgId: githubAccount.id,
        orgId,
      });
      return buildRedirectForError(
        stateData,
        providerName,
        "github_org_bound_to_other"
      );
    }

    log.info("[oauth/callback] GitHub binding created", {
      githubOrgId: githubAccount.id,
      orgId,
    });
  } else if (bindingAction.action === "reinstate") {
    await db
      .update(githubOrgBindings)
      .set({
        status: "active",
        installationId: installation.id,
        githubOrgLogin: githubAccount.login,
        githubOrgAvatarUrl: githubAccount.avatarUrl ?? null,
        updatedAt: new Date().toISOString(),
      })

      .where(eq(githubOrgBindings.id, bindingAction.bindingId));
    log.info("[oauth/callback] GitHub binding reinstated", {
      githubOrgId: githubAccount.id,
      orgId,
    });
  }
}
