import { relations } from "drizzle-orm";
import { gatewayInstallations } from "./tables/gateway-installations";
import { gatewayLifecycleLogs } from "./tables/gateway-lifecycle-log";
import { gatewayTokens } from "./tables/gateway-tokens";
import { orgEntities } from "./tables/org-entities";
import { orgEntityEdges } from "./tables/org-entity-edges";
import { orgEventEntities } from "./tables/org-event-entities";
import { orgEvents } from "./tables/org-events";
import { orgIntegrations } from "./tables/org-integrations";

/**
 * Define relations between tables for Drizzle ORM queries
 *
 * Note: Organizations are managed by Clerk, not in our database.
 * Tables reference Clerk org IDs via clerkOrgId fields (no FK constraints).
 */

// Gateway relations
export const gatewayInstallationsRelations = relations(
  gatewayInstallations,
  ({ many }) => ({
    tokens: many(gatewayTokens),
    orgIntegrations: many(orgIntegrations),
    lifecycleLogs: many(gatewayLifecycleLogs),
  })
);

export const gatewayLifecycleLogsRelations = relations(
  gatewayLifecycleLogs,
  ({ one }) => ({
    installation: one(gatewayInstallations, {
      fields: [gatewayLifecycleLogs.installationId],
      references: [gatewayInstallations.id],
    }),
  })
);

export const gatewayTokensRelations = relations(gatewayTokens, ({ one }) => ({
  installation: one(gatewayInstallations, {
    fields: [gatewayTokens.installationId],
    references: [gatewayInstallations.id],
  }),
}));

export const orgIntegrationsRelations = relations(
  orgIntegrations,
  ({ one }) => ({
    installation: one(gatewayInstallations, {
      fields: [orgIntegrations.installationId],
      references: [gatewayInstallations.id],
    }),
  })
);

export const orgEventsRelations = relations(orgEvents, ({ many }) => ({
  entityEvents: many(orgEventEntities),
}));

// Entity-event junction relations
export const orgEventEntitiesRelations = relations(
  orgEventEntities,
  ({ one }) => ({
    entity: one(orgEntities, {
      fields: [orgEventEntities.entityId],
      references: [orgEntities.id],
    }),
    event: one(orgEvents, {
      fields: [orgEventEntities.eventId],
      references: [orgEvents.id],
    }),
  })
);

// Entity↔entity edges relations
export const orgEntityEdgesRelations = relations(orgEntityEdges, ({ one }) => ({
  sourceEntity: one(orgEntities, {
    fields: [orgEntityEdges.sourceEntityId],
    references: [orgEntities.id],
  }),
  targetEntity: one(orgEntities, {
    fields: [orgEntityEdges.targetEntityId],
    references: [orgEntities.id],
  }),
  sourceEvent: one(orgEvents, {
    fields: [orgEntityEdges.sourceEventId],
    references: [orgEvents.id],
  }),
}));

import { z } from "zod";
import type { ProviderApi, RateLimit } from "../../provider/api";
import { createRS256JWT } from "../../runtime/jwt";
import type { GitHubConfig } from "./auth";

// ── Response Schemas ────────────────────────────────────────────────────────────

export const githubUserSchema = z
  .object({
    login: z.string(),
    id: z.number(),
    avatar_url: z.string().optional(),
    html_url: z.string().optional(),
  })
  .loose();

export const githubPullRequestSchema = z
  .object({
    id: z.number(),
    number: z.number(),
    title: z.string(),
    state: z.string(),
    body: z.string().nullable(),
    user: githubUserSchema.nullable(),
    created_at: z.string(),
    updated_at: z.string(),
    merged_at: z.string().nullable(),
    merged: z.boolean().nullable().optional(),
    merge_commit_sha: z.string().nullable(),
    draft: z.boolean(),
    html_url: z.string(),
    head: z.object({ ref: z.string(), sha: z.string() }).loose(),
    base: z.object({ ref: z.string(), sha: z.string() }).loose(),
    // List API omits these — present only on individual PR fetch
    additions: z.number().optional(),
    deletions: z.number().optional(),
    changed_files: z.number().optional(),
  })
  .loose();

export const githubIssueSchema = z
  .object({
    id: z.number(),
    number: z.number(),
    title: z.string(),
    state: z.string(),
    state_reason: z.string().nullable().optional(),
    body: z.string().nullable(),
    user: githubUserSchema.nullable(),
    created_at: z.string(),
    updated_at: z.string(),
    closed_at: z.string().nullable(),
    html_url: z.string(),
    pull_request: z.unknown().optional(),
    labels: z.array(z.object({ name: z.string() }).loose()).optional(),
  })
  .loose();

export const githubAppInstallationSchema = z
  .object({
    id: z.number(),
    account: z
      .object({
        login: z.string(),
        type: z.string(),
        avatar_url: z.string().optional(),
      })
      .nullable()
      .optional(),
  })
  .loose();

// ── App JWT Builder ──────────────────────────────────────────────────────────────

async function buildGitHubAppAuth(config: unknown): Promise<string> {
  const c = config as GitHubConfig;
  const now = Math.floor(Date.now() / 1000);
  return createRS256JWT(
    { iss: c.appId, iat: now - 60, exp: now + 600 },
    c.privateKey
  );
}

// ── Rate Limit Parser ───────────────────────────────────────────────────────────

export function parseGitHubRateLimit(headers: Headers): RateLimit | null {
  const remaining = headers.get("x-ratelimit-remaining");
  const reset = headers.get("x-ratelimit-reset");
  const limit = headers.get("x-ratelimit-limit");
  if (!(remaining && reset && limit)) {
    return null;
  }
  const r = Number.parseInt(remaining, 10);
  const s = Number.parseInt(reset, 10);
  const l = Number.parseInt(limit, 10);
  if (Number.isNaN(r) || Number.isNaN(s) || Number.isNaN(l)) {
    return null;
  }
  return { remaining: r, resetAt: new Date(s * 1000), limit: l };
}

export const githubInstallationReposSchema = z
  .object({
    total_count: z.number(),
    repositories: z.array(
      z
        .object({
          id: z.number(),
          name: z.string(),
          full_name: z.string(),
          private: z.boolean(),
          description: z.string().nullable(),
          default_branch: z.string(),
          archived: z.boolean(),
          html_url: z.string(),
          language: z.string().nullable().optional(),
          stargazers_count: z.number().optional(),
          updated_at: z.string().nullable().optional(),
          owner: z.object({ login: z.string() }).loose(),
        })
        .loose()
    ),
  })
  .loose();

// ── API Definition ──────────────────────────────────────────────────────────────

export const githubApi = {
  baseUrl: "https://api.github.com",
  defaultHeaders: { Accept: "application/vnd.github.v3+json" },
  parseRateLimit: parseGitHubRateLimit,
  endpoints: {
    "get-app-installation": {
      method: "GET",
      path: "/app/installations/{installation_id}",
      description:
        "Get a GitHub App installation by installation ID (requires App JWT)",
      responseSchema: githubAppInstallationSchema,
      buildAuth: buildGitHubAppAuth,
    },
    "list-installation-repos": {
      method: "GET",
      path: "/installation/repositories",
      description:
        "List repositories accessible to the GitHub App installation",
      responseSchema: githubInstallationReposSchema,
    },
    "get-repo": {
      method: "GET",
      path: "/repos/{owner}/{repo}",
      description: "Get repository metadata including default branch",
      responseSchema: z.object({ default_branch: z.string() }).loose(),
    },
    "get-file-contents": {
      method: "GET",
      path: "/repos/{owner}/{repo}/contents/{path}",
      description: "Get file contents from a repository",
      responseSchema: z.union([
        z
          .object({
            type: z.string(),
            content: z.string(),
            sha: z.string(),
            size: z.number().optional(),
          })
          .loose(),
        z.array(z.object({ type: z.string(), name: z.string() }).loose()),
      ]),
    },
    "list-pull-requests": {
      method: "GET",
      path: "/repos/{owner}/{repo}/pulls",
      description: "List pull requests for a repository",
      responseSchema: z.array(githubPullRequestSchema),
    },
    "list-issues": {
      method: "GET",
      path: "/repos/{owner}/{repo}/issues",
      description:
        "List issues for a repository (includes PRs — filter client-side)",
      responseSchema: z.array(githubIssueSchema),
    },
  },
} as const satisfies ProviderApi;

import { z } from "zod";
import { syncSchema } from "../../provider/primitives";

// ── Raw OAuth Response Shape ──

/**
 * Raw shape stored in providerAccountInfo.raw for GitHub.
 *
 * Convention: raw = non-secret fields from the token exchange / OAuth response.
 * GitHub App flow has no token exchange response, so raw is empty.
 * Display data (account login, avatar, type) is resolved live in
 * connections.github.list via GET /app/installations/{id}.
 */
export const githubInstallationRawSchema = z.object({});

export type GitHubInstallationRaw = z.infer<typeof githubInstallationRawSchema>;

// ── Account Info Schema ──

export const githubAccountInfoSchema = z.object({
  version: z.literal(1),
  events: z.array(z.string()),
  installedAt: z.string(),
  lastValidatedAt: z.string(),
  sourceType: z.literal("github"),
  raw: githubInstallationRawSchema,
});

export type GitHubAccountInfo = z.infer<typeof githubAccountInfoSchema>;

// ── Config Schema ──

export const githubConfigSchema = z.object({
  appSlug: z.string(),
  appId: z.string(),
  privateKey: z.string(),
  clientId: z.string(),
  clientSecret: z.string(),
  webhookSecret: z.string(),
});

export type GitHubConfig = z.infer<typeof githubConfigSchema>;

// ── OAuth Response Schema ──

export const githubOAuthResponseSchema = z.union([
  z.object({
    access_token: z.string(),
    token_type: z.string(),
    scope: z.string(),
  }),
  z.object({
    error: z.string(),
    error_description: z.string(),
    error_uri: z.string(),
  }),
]);

// ── Provider Config Schema ──

/**
 * Stable connection config stored as JSONB in gateway_installations.provider_config.
 *
 * ONLY stable provider-issued IDs and user-controlled settings belong here.
 *
 * NEVER add display names (repoName, orgName, slug, description, visibility)
 * — these change on the provider side without our involvement and become stale.
 * Resolve display data from a cache layer keyed on the stable IDs stored here.
 */
export const githubProviderConfigSchema = z.object({
  provider: z.literal("github"),
  type: z.literal("repository"),
  sync: syncSchema,
  status: z
    .object({
      configStatus: z.enum(["configured", "awaiting_config"]).optional(),
      configPath: z.string().optional(),
      lastConfigCheck: z.string().optional(),
    })
    .optional(),
});

export type GithubProviderConfig = z.infer<typeof githubProviderConfigSchema>;

import type { ProviderAccountInfo, SourceType } from "@repo/app-providers";
import type { GwInstallationBackfillConfig } from "@repo/app-providers/contracts";
import type { ClerkUserId } from "@repo/app-validation";
import { nanoid } from "@repo/lib";
import { sql } from "drizzle-orm";
import {
  index,
  integer,
  jsonb,
  pgTable,
  timestamp,
  uniqueIndex,
  varchar,
} from "drizzle-orm/pg-core";

export const gatewayInstallations = pgTable(
  "lightfast_gateway_installations",
  {
    id: varchar("id", { length: 191 })
      .notNull()
      .primaryKey()
      .$defaultFn(() => nanoid()),

    provider: varchar("provider", { length: 50 }).notNull().$type<SourceType>(),
    externalId: varchar("external_id", { length: 191 }).notNull(),
    connectedBy: varchar("connected_by", { length: 191 })
      .notNull()
      .$type<ClerkUserId>(),
    orgId: varchar("org_id", { length: 191 }).notNull(),

    status: varchar("status", { length: 50 }).notNull(), // active|pending|error|revoked

    /**
     * Provider-specific installation metadata (JSONB) — discriminated union by sourceType.
     *
     * Schema: providerAccountInfoSchema from @repo/app-providers
     *
     * DESIGN INVARIANT:
     * - `raw` = non-secret fields from the token exchange / OAuth response only
     * - NEVER store display names (account login, org name, avatar, slug) here
     * - Display data is resolved live via provider APIs in connections.*.list/get
     * - This column stores identity + operational data, not presentation data
     *
     * NEVER add resource-specific data (repos[], projects[], teams[]) — those
     * belong in providerConfig on gateway_installations, one row per resource.
     */
    providerAccountInfo: jsonb(
      "provider_account_info"
    ).$type<ProviderAccountInfo>(),

    /** Optional backfill configuration for this installation. */
    backfillConfig:
      jsonb("backfill_config").$type<GwInstallationBackfillConfig>(),

    // Health monitoring columns
    healthStatus: varchar("health_status", { length: 50 })
      .notNull()
      .default("unknown"),
    lastHealthCheckAt: timestamp("last_health_check_at", {
      mode: "string",
      withTimezone: true,
    }),
    healthCheckFailures: integer("health_check_failures").notNull().default(0),

    createdAt: timestamp("created_at", { mode: "string", withTimezone: true })
      .notNull()
      .defaultNow(),
    updatedAt: timestamp("updated_at", { mode: "string", withTimezone: true })
      .notNull()
      .defaultNow()
      .$onUpdateFn(() => sql`CURRENT_TIMESTAMP`),
  },
  (table) => ({
    providerExternalIdx: uniqueIndex("gateway_inst_provider_external_idx").on(
      table.provider,
      table.externalId
    ),
    orgIdIdx: index("gateway_inst_org_id_idx").on(table.orgId),
    orgProviderIdx: index("gateway_inst_org_provider_idx").on(
      table.orgId,
      table.provider
    ),
    connectedByIdx: index("gateway_inst_connected_by_idx").on(
      table.connectedBy
    ),
  })
);

export type GatewayInstallation = typeof gatewayInstallations.$inferSelect;
export type InsertGatewayInstallation =
  typeof gatewayInstallations.$inferInsert;

