import { db } from "@db/app/client";
import { githubOrgBindings } from "@db/app/schema";
import {
  createGitHubAppJWT,
  githubAppInstallationSchema,
} from "@repo/app-providers";
import type { GitHubConfig } from "@repo/app-providers";
import { eq } from "@vendor/db";
import { log } from "@vendor/observability/log/next";

export interface GitHubAccount {
  id: number;
  login: string;
  avatarUrl: string | undefined;
  type: string;
}

/**
 * Fetch the GitHub account (org/user) that owns a given installation.
 * Uses the GitHub App JWT (not an installation token).
 * Pattern: mirrors healthCheck.check at github/index.ts:278-298.
 */
export async function resolveGitHubAccount(
  config: unknown,
  installationId: string
): Promise<GitHubAccount> {
  const jwt = await createGitHubAppJWT(config as GitHubConfig);
  const response = await fetch(
    `https://api.github.com/app/installations/${installationId}`,
    {
      headers: {
        Authorization: `Bearer ${jwt}`,
        Accept: "application/vnd.github+json",
        "User-Agent": "lightfast-platform",
        "X-GitHub-Api-Version": "2022-11-28",
      },
      signal: AbortSignal.timeout(10_000),
    }
  );

  if (!response.ok) {
    throw new Error(
      `Failed to fetch installation ${installationId}: ${response.status}`
    );
  }

  const data = githubAppInstallationSchema.parse(await response.json());
  if (!data.account) {
    throw new Error(`Installation ${installationId} has no account`);
  }

  return {
    id: data.account.id,
    login: data.account.login,
    avatarUrl: data.account.avatar_url,
    type: data.account.type,
  };
}

export type BindingAction =
  | { action: "create" }
  | { action: "reinstate"; bindingId: string }
  | {
      action: "reject";
      reason: "github_org_bound_to_other" | "org_already_bound";
    };

/**
 * Check the github_org_bindings table and determine what action to take.
 *
 * Rules:
 * - If github_org_id is bound to this org → reinstate
 * - If github_org_id is bound to a different org → reject
 * - If this org is bound to a different github org → reject
 * - If no binding exists → create
 */
export async function enforceGitHubBinding(
  orgId: string,
  githubOrgId: string
): Promise<BindingAction> {
  // Check 1: Is this GitHub org already bound?
  const byGithub = await db
    .select({
      id: githubOrgBindings.id,
      clerkOrgId: githubOrgBindings.clerkOrgId,
    })
    .from(githubOrgBindings)
    .where(eq(githubOrgBindings.githubOrgId, githubOrgId))
    .limit(1);

  if (byGithub[0]) {
    if (byGithub[0].clerkOrgId === orgId) {
      return { action: "reinstate", bindingId: byGithub[0].id };
    }
    log.warn("[github-binding] GitHub org already bound to different org", {
      githubOrgId,
      boundTo: byGithub[0].clerkOrgId,
      requestedBy: orgId,
    });
    return { action: "reject", reason: "github_org_bound_to_other" };
  }

  // Check 2: Is this Lightfast org already bound to a different GitHub org?
  const byOrg = await db
    .select({ id: githubOrgBindings.id })
    .from(githubOrgBindings)
    .where(eq(githubOrgBindings.clerkOrgId, orgId))
    .limit(1);

  if (byOrg[0]) {
    log.warn("[github-binding] Org already bound to different GitHub org", {
      orgId,
      existingBinding: byOrg[0].id,
    });
    return { action: "reject", reason: "org_already_bound" };
  }

  return { action: "create" };
}

