"use client";

import { CheckCircle2 } from "lucide-react";
import { useEffect } from "react";

/**
 * GitHub OAuth Success Page
 *
 * Displayed in popup window after successful GitHub App installation and OAuth.
 * Shows confirmation message and instructs user to close the window.
 *
 * The parent window detects popup close and refetches integration data.
 */
export default function GitHubConnectedPage() {
  useEffect(() => {
    // Notify parent via BroadcastChannel (works regardless of window.opener / COOP)
    const channel = new BroadcastChannel("oauth-connections");
    channel.postMessage({ type: "github_connected" });
    channel.close();

    // Also try postMessage (works when opener is available)
    const opener = window.opener as Window | null;
    if (opener) {
      try {
        opener.postMessage(
          { type: "github_connected" },
          window.location.origin
        );
      } catch {
        // Guard against SecurityError under strict COOP/COEP or sandboxed iframes
      }
    }

    // Auto-close after 2 seconds
    const timer = setTimeout(() => {
      window.close();
    }, 2000);

    return () => clearTimeout(timer);
  }, []);

  return (
    <div className="flex min-h-screen items-center justify-center bg-background">
      <div className="space-y-6 p-8 text-center">
        {/* Success Icon */}
        <div className="flex justify-center">
          <div className="rounded-full bg-green-500/10 p-4">
            <CheckCircle2 className="h-16 w-16 text-green-500" />
          </div>
        </div>

        {/* Success Message */}
        <div className="space-y-2">
          <h1 className="font-semibold text-2xl text-foreground">
            GitHub Connected!
          </h1>
          <p className="text-muted-foreground">
            Your GitHub account has been successfully connected.
          </p>
        </div>

        {/* Close Instructions */}
        <div className="space-y-2">
          <p className="text-muted-foreground text-sm">
            This window will close automatically...
          </p>
          <button
            className="text-primary text-sm hover:underline"
            onClick={() => window.close()}
            type="button"
          >
            Or click here to close now
          </button>
        </div>
      </div>
    </div>
  );
}

